32	const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';
33	
34	function categoryColorOr(bundle: ViewportPaintBundle | null, cat: ElementCategoryToken): string {
35	  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
36	}
