118	function elevationMForLevel(levelId: string, elementsById: Record<string, Element>): number {
119	  const lvl = elementsById[levelId];
120	  if (!lvl || lvl.kind !== 'level') return 0;
121	  return lvl.elevationMm / 1000;
122	}
