124	function hostedXZ(
125	  hosted: Extract<Element, { kind: 'door' } | { kind: 'window' }>,
126	  wall: WallElem,
127	): { px: number; pz: number } {
128	  const sx = wall.start.xMm / 1000;
129	  const sz = wall.start.yMm / 1000;
130	  const dx = wall.end.xMm / 1000 - sx;
131	  const dz = wall.end.yMm / 1000 - sz;
132	  const len = Math.max(1e-6, Math.hypot(dx, dz));
133	  const ux = dx / len;
134	  const uz = dz / len;
135	  return {
136	    px: sx + ux * hosted.alongT * len,
137	    pz: sz + uz * hosted.alongT * len,
138	  };
139	}
140	
141	function wallYaw(wall: WallElem) {
142	  const sx = wall.start.xMm / 1000;
143	  const sz = wall.start.yMm / 1000;
144	  const ex = wall.end.xMm / 1000;
145	  const ez = wall.end.yMm / 1000;
146	  return Math.atan2(ez - sz, ex - sx);
147	}
