149	function makeFloorSlabMesh(
150	  floor: Extract<Element, { kind: 'floor' }>,
151	  elementsById: Record<string, Element>,
152	  paint: ViewportPaintBundle | null,
153	): THREE.Mesh {
154	  const b = xzBoundsMm(floor.boundaryMm ?? []);
155	
156	  const elev = elevationMForLevel(floor.levelId, elementsById);
157	
158	  const th = THREE.MathUtils.clamp(floor.thicknessMm / 1000, 0.05, 1.8);
159	
160	  const mesh = new THREE.Mesh(
161	    new THREE.BoxGeometry(b.spanX / 1000, th, b.spanZ / 1000),
162	
163	    new THREE.MeshStandardMaterial({
164	      color: categoryColorOr(paint, 'floor'),
165	      roughness: paint?.categories.floor.roughness ?? 0.9,
166	      transparent: true,
167	      opacity: 0.92,
168	    }),
169	  );
170	
171	  mesh.position.set(b.cx / 1000, elev + th / 2, b.cz / 1000);
172	
173	  mesh.userData.bimPickId = floor.id;
174	
175	  return mesh;
176	}
