178	function makeRoofMassMesh(
179	  roof: Extract<Element, { kind: 'roof' }>,
180	  elementsById: Record<string, Element>,
181	  paint: ViewportPaintBundle | null,
182	): THREE.Mesh {
183	  const b = xzBoundsMm(roof.footprintMm ?? []);
184	
185	  const ov = THREE.MathUtils.clamp((roof.overhangMm ?? 0) / 1000, 0, 5);
186	
187	  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
188	
189	  // Eave plate = top of the tallest wall at the reference level.
190	  // Without this the proxy sits inside the upper-storey walls and is invisible.
191	  const wallsAtRefLevel = Object.values(elementsById).filter(
192	    (e): e is WallElem => e.kind === 'wall' && (e as WallElem).levelId === roof.referenceLevelId,
193	  );
194	  const wallTopM =
195	    wallsAtRefLevel.length > 0
196	      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
197	      : 0;
198	  const eaveY = refElev + wallTopM;
199	
200	  const slopeRad = (THREE.MathUtils.clamp(Number(roof.slopeDeg ?? 25), 5, 70) * Math.PI) / 180;
201	
202	  // Ridge along longer plan axis; slope drops along shorter axis.
203	  const spanXm = b.spanX / 1000;
204	  const spanZm = b.spanZ / 1000;
205	  const halfSpan = Math.min(spanXm, spanZm) / 2;
206	  const ridgeY = eaveY + halfSpan * Math.tan(slopeRad);
207	
208	  // Eave corners with overhang (THREE.js: plan X→X, plan Y→Z)
209	  const ox0 = b.minX / 1000 - ov;
210	  const ox1 = b.maxX / 1000 + ov;
211	  const oz0 = b.minZ / 1000 - ov;
212	  const oz1 = b.maxZ / 1000 + ov;
213	
214	  let positions: number[];
215	
216	  if (spanXm >= spanZm) {
217	    // Ridge east-west (along X); slopes drop north and south
218	    const rz = b.cz / 1000;
219	    positions = [
220	      // South slope
221	      ox0, eaveY, oz0,  ox1, eaveY, oz0,  ox0, ridgeY, rz,
222	      ox1, eaveY, oz0,  ox1, ridgeY, rz,  ox0, ridgeY, rz,
223	      // North slope
224	      ox0, ridgeY, rz,  ox1, ridgeY, rz,  ox0, eaveY, oz1,
225	      ox1, ridgeY, rz,  ox1, eaveY, oz1,  ox0, eaveY, oz1,
226	      // West gable
227	      ox0, eaveY, oz0,  ox0, ridgeY, rz,  ox0, eaveY, oz1,
228	      // East gable
229	      ox1, eaveY, oz0,  ox1, eaveY, oz1,  ox1, ridgeY, rz,
230	    ];
231	  } else {
232	    // Ridge north-south (along Z); slopes drop east and west
233	    const rx = b.cx / 1000;
234	    positions = [
235	      // West slope
236	      ox0, eaveY, oz0,  rx, ridgeY, oz0,  ox0, eaveY, oz1,
237	      rx, ridgeY, oz0,  rx, ridgeY, oz1,  ox0, eaveY, oz1,
238	      // East slope
239	      rx, ridgeY, oz0,  ox1, eaveY, oz0,  ox1, eaveY, oz1,
240	      rx, ridgeY, oz0,  ox1, eaveY, oz1,  rx, ridgeY, oz1,
241	      // South gable
242	      ox0, eaveY, oz0,  ox1, eaveY, oz0,  rx, ridgeY, oz0,
243	      // North gable
244	      ox0, eaveY, oz1,  rx, ridgeY, oz1,  ox1, eaveY, oz1,
245	    ];
246	  }
247	
248	  const geom = new THREE.BufferGeometry();
249	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
250	  geom.computeVertexNormals();
251	
252	  const mesh = new THREE.Mesh(
253	    geom,
254	    new THREE.MeshStandardMaterial({
255	      color: categoryColorOr(paint, 'roof'),
256	      transparent: true,
257	      opacity: 0.94,
258	      roughness: paint?.categories.roof.roughness ?? 0.74,
259	      metalness: 0.04,
260	      side: THREE.DoubleSide,
261	    }),
262	  );
263	  mesh.userData.bimPickId = roof.id;
264	  return mesh;
265	}
