267	function makeStairVolumeMesh(
268	  stair: Extract<Element, { kind: 'stair' }>,
269	  elementsById: Record<string, Element>,
270	  paint: ViewportPaintBundle | null,
271	  selectedId?: string,
272	): THREE.Mesh {
273	  const sx = stair.runStartMm.xMm / 1000;
274	
275	  const sz = stair.runStartMm.yMm / 1000;
276	
277	  const ex = stair.runEndMm.xMm / 1000;
278	
279	  const ez = stair.runEndMm.yMm / 1000;
280	
281	  const dx = ex - sx;
282	
283	  const dz = ez - sz;
284	
285	  const len = Math.max(1e-3, Math.hypot(dx, dz));
286	
287	  const width = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
288	
289	  const bl = elementsById[stair.baseLevelId];
290	
291	  const tl = elementsById[stair.topLevelId];
292	
293	  const riseMm =
294	    bl?.kind === 'level' && tl?.kind === 'level'
295	      ? Math.abs(tl.elevationMm - bl.elevationMm)
296	      : stair.riserMm * 16;
297	
298	  const rise = THREE.MathUtils.clamp(riseMm / 1000, 0.5, 12);
299	
300	  const elevBase = elevationMForLevel(stair.baseLevelId, elementsById);
301	
302	  const mesh = new THREE.Mesh(
303	    new THREE.BoxGeometry(len, rise, width),
304	
305	    new THREE.MeshStandardMaterial({
306	      color:
307	        stair.id === selectedId
308	          ? (paint?.selection.selectedColor ?? '#fcd34d')
309	          : categoryColorOr(paint, 'stair'),
310	    }),
311	  );
312	
313	  mesh.position.set(sx + dx / 2, elevBase + rise / 2, sz + dz / 2);
314	
315	  mesh.rotation.y = Math.atan2(dx, dz);
316	
317	  mesh.userData.bimPickId = stair.id;
318	
319	  return mesh;
320	}
