322	function makeWallMesh(
323	  wall: WallElem,
324	  elevM: number,
325	  paint: ViewportPaintBundle | null,
326	  selectedId?: string,
327	): THREE.Mesh {
328	  const sx = wall.start.xMm / 1000;
329	  const sz = wall.start.yMm / 1000;
330	  const ex = wall.end.xMm / 1000;
331	  const ez = wall.end.yMm / 1000;
332	  const dx = ex - sx;
333	  const dz = ez - sz;
334	  const len = Math.max(0.001, Math.hypot(dx, dz));
335	  const height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
336	  const thick = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
337	  const mesh = new THREE.Mesh(
338	    new THREE.BoxGeometry(len, height, thick),
339	    new THREE.MeshStandardMaterial({
340	      color:
341	        wall.id === selectedId
342	          ? (paint?.selection.selectedColor ?? '#fb923c')
343	          : categoryColorOr(paint, 'wall'),
344	      roughness: paint?.categories.wall.roughness ?? 0.85,
345	    }),
346	  );
347	  mesh.position.set(sx + dx / 2, elevM + height / 2, sz + dz / 2);
348	  mesh.rotation.y = Math.atan2(dz, dx);
349	  mesh.userData.bimPickId = wall.id;
350	  return mesh;
351	}
