353	function makeDoorMesh(
354	  door: Extract<Element, { kind: 'door' }>,
355	  wall: WallElem,
356	  elevM: number,
357	  paint: ViewportPaintBundle | null,
358	  sid?: string,
359	) {
360	  const { px, pz } = hostedXZ(door, wall);
361	  const height = THREE.MathUtils.clamp((wall.heightMm / 1000) * 0.86, 0.6, 2.2);
362	  const width = THREE.MathUtils.clamp(door.widthMm / 1000, 0.35, 4);
363	  const depth = THREE.MathUtils.clamp(wall.thicknessMm / 1000 + 0.08, 0.08, 2);
364	  const mesh = new THREE.Mesh(
365	    new THREE.BoxGeometry(width, height, depth),
366	    new THREE.MeshStandardMaterial({
367	      color:
368	        door.id === sid
369	          ? (paint?.selection.selectedColor ?? '#fde047')
370	          : categoryColorOr(paint, 'door'),
371	    }),
372	  );
373	  mesh.position.set(px, elevM + height / 2, pz);
374	  mesh.rotation.y = wallYaw(wall);
375	  mesh.userData.bimPickId = door.id;
376	  return mesh;
377	}
