379	function makeWindowMesh(
380	  win: Extract<Element, { kind: 'window' }>,
381	  wall: WallElem,
382	  elevM: number,
383	  paint: ViewportPaintBundle | null,
384	  sid?: string,
385	) {
386	  const { px, pz } = hostedXZ(win, wall);
387	  const sill = THREE.MathUtils.clamp(win.sillHeightMm / 1000, 0.06, wall.heightMm / 1000 - 0.08);
388	  const h = THREE.MathUtils.clamp(win.heightMm / 1000, 0.05, wall.heightMm / 1000 - sill - 0.06);
389	  const width = THREE.MathUtils.clamp(win.widthMm / 1000, 0.14, 4);
390	  const depth = THREE.MathUtils.clamp(wall.thicknessMm / 1000 + 0.02, 0.06, 1.5);
391	  const mesh = new THREE.Mesh(
392	    new THREE.BoxGeometry(width, h, depth),
393	    new THREE.MeshStandardMaterial({
394	      transparent: true,
395	      opacity: 0.84,
396	      color:
397	        win.id === sid
398	          ? (paint?.selection.selectedColor ?? '#ddd6fe')
399	          : categoryColorOr(paint, 'window'),
400	    }),
401	  );
402	  mesh.position.set(px, elevM + sill + h / 2, pz);
403	  mesh.rotation.y = wallYaw(wall);
404	  mesh.userData.bimPickId = win.id;
405	  return mesh;
406	}
