408	function makeRoomRibbon(
409	  room: Extract<Element, { kind: 'room' }>,
410	  elevM: number,
411	  paint: ViewportPaintBundle | null,
412	) {
413	  const pts = room.outlineMm.map(
414	    (p) => new THREE.Vector3(p.xMm / 1000, elevM + 0.035, p.yMm / 1000),
415	  );
416	  const geom = new THREE.BufferGeometry().setFromPoints(pts);
417	  const loop = new THREE.LineLoop(
