448	function computeRootBoundingBox(
449	  root: THREE.Object3D,
450	): { min: { x: number; y: number; z: number }; max: { x: number; y: number; z: number } } | null {
451	  const box = new THREE.Box3().setFromObject(root);
452	  if (!Number.isFinite(box.min.x) || !Number.isFinite(box.max.x)) return null;
453	  return {
454	    min: { x: box.min.x, y: box.min.y, z: box.min.z },
455	    max: { x: box.max.x, y: box.max.y, z: box.max.z },
456	  };
457	}
