459	function aabbWireframeVertices(
460	  min: { x: number; y: number; z: number },
461	  max: { x: number; y: number; z: number },
462	): THREE.Vector3[] {
463	  const v = (x: number, y: number, z: number): THREE.Vector3 => new THREE.Vector3(x, y, z);
464	  const c000 = v(min.x, min.y, min.z);
465	  const c100 = v(max.x, min.y, min.z);
466	  const c010 = v(min.x, max.y, min.z);
467	  const c110 = v(max.x, max.y, min.z);
468	  const c001 = v(min.x, min.y, max.z);
469	  const c101 = v(max.x, min.y, max.z);
470	  const c011 = v(min.x, max.y, max.z);
471	  const c111 = v(max.x, max.y, max.z);
472	  // 12 edges as vertex pairs.
473	  return [
474	    c000,
475	    c100,
476	    c100,
477	    c110,
478	    c110,
479	    c010,
480	    c010,
481	    c000,
482	    c001,
483	    c101,
484	    c101,
485	    c111,
486	    c111,
487	    c011,
488	    c011,
489	    c001,
490	    c000,
491	    c001,
492	    c100,
493	    c101,
494	    c110,
495	    c111,
496	    c010,
497	    c011,
498	  ];
499	}
