501	function applyClippingPlanesToMeshes(root: THREE.Object3D, planes: THREE.Plane[]) {
502	  if (!planes.length) return;
503	  root.traverse((node) => {
504	    const mesh = node as THREE.Mesh;
505	    if (mesh.isMesh && mesh.material instanceof THREE.MeshStandardMaterial) {
506	      const m = mesh.material.clone();
507	      m.clippingPlanes = planes.slice();
508	      mesh.material = m;
509	    }
510	  });
511	}
