513	export function Viewport({ wsConnected, onPersistViewpointField }: Props) {
514	  void wsConnected;
515	
516	  const mountRef = useRef<HTMLDivElement | null>(null);
517	  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
518	  const sceneRef = useRef<THREE.Scene | null>(null);
519	  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);
520	  const rootGroupRef = useRef<THREE.Group | null>(null);
521	  const rafRef = useRef<number | null>(null);
522	  /** Live paint bundle for the rendered scene. Rebuilt on theme change. */
523	  const paintBundleRef = useRef<ViewportPaintBundle | null>(null);
524	  /** Live CameraRig instance — replaces the legacy ad-hoc spherical rig. */
525	  const cameraRigRef = useRef<CameraRig | null>(null);
526	  /** Set by the mount effect so we can snap the orbit rig to saved `viewpoint` cameras. */
527	  const orbitRigApiRef = useRef<{
528	    applyViewpointMm: (pose: {
529	      position: { xMm: number; yMm: number; zMm: number };
530	      target: { xMm: number; yMm: number; zMm: number };
531	      up: { xMm: number; yMm: number; zMm: number };
532	    }) => void;
533	  } | null>(null);
534	
535	  const [currentAzimuth, setCurrentAzimuth] = useState(Math.PI / 4);
536	  const [currentElevation, setCurrentElevation] = useState(0.45);
537	  const [walkActive, setWalkActive] = useState(false);
538	  const [sectionBoxActive, setSectionBoxActive] = useState(false);
539	  const walkControllerRef = useRef<WalkController | null>(null);
540	  const sectionBoxRef = useRef<SectionBox | null>(null);
541	  const sectionBoxCageRef = useRef<THREE.LineSegments | null>(null);
542	
543	  const elementsById = useBimStore((s) => s.elementsById);
544	  const theme = useTheme();
545	
546	  const selectedId = useBimStore((s) => s.selectedId);
547	
548	  const viewerCategoryHidden = useBimStore((s) => s.viewerCategoryHidden);
549	
550	  const viewerClipElevMm = useBimStore((s) => s.viewerClipElevMm);
551	  const viewerClipFloorElevMm = useBimStore((s) => s.viewerClipFloorElevMm);
552	  const orbitCameraNonce = useBimStore((s) => s.orbitCameraNonce);
553	  const orbitCameraPoseMm = useBimStore((s) => s.orbitCameraPoseMm);
554	  const activeViewpointId = useBimStore((s) => s.activeViewpointId);
555	
556	  const persistedOrbitViewpoint = useMemo(() => {
557	    const id = activeViewpointId;
558	    if (!id) return null;
559	    const el = elementsById[id];
560	    if (!el || el.kind !== 'viewpoint' || el.mode !== 'orbit_3d') return null;
561	    return el;
562	  }, [activeViewpointId, elementsById]);
563	
564	  useEffect(() => {
565	    const el = mountRef.current;
566	    if (!el) return;
567	    const host = el;
568	
569	    /** Resolve drafting + lighting tokens once at mount; theme switches will
570	     * trigger a rebuild via the dependency on `elementsById` etc. */
571	    const paint = resolveViewportPaintBundle();
572	    paintBundleRef.current = paint;
573	
574	    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
575	    renderer.localClippingEnabled = true;
576	    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
577	    renderer.setClearColor(readColorToken('--color-background', '#ffffff'), 1);
578	    rendererRef.current = renderer;
579	    host.appendChild(renderer.domElement);
580	
581	    const scene = new THREE.Scene();
