function ScheduleGrid({
  schedule,
}: {
  schedule: Extract<Element, { kind: 'schedule' }>;
}): JSX.Element {
  return (
    <div className="flex flex-col gap-3">
      <div>
        <div className="text-md font-medium text-foreground">{schedule.name}</div>
        <div className="text-xs text-muted">
