268	  const beginResize = (e: ReactPointerEvent<SVGRectElement>, index: number) => {
269	    if (!authoring) return;
270	    e.preventDefault();
271	    e.stopPropagation();
272	    const svg = svgRef.current;
273	    if (!svg) return;
274	    const row = vpDrafts[index];
275	    if (!row || row.viewportLocked) return;
276	    resizeRef.current = { index };
277	
278	    const onMove = (ev: PointerEvent) => {
279	      const rr = resizeRef.current;
280	      const el = svgRef.current;
281	      if (!rr || !el) return;
282	      const pt = clientToSvgMm(el, ev.clientX, ev.clientY);
283	      setVpDrafts((prev) => {
284	        const row = prev[rr.index];
285	        if (!row) return prev;
286	        const nwRaw = pt.x - row.xMm;
287	        const nhRaw = pt.y - row.yMm;
288	        const nextBox = clampViewportMmBox(wMm, hMm, {
289	          xMm: row.xMm,
290	          yMm: row.yMm,
291	          widthMm: nwRaw,
292	          heightMm: nhRaw,
293	        });
294	        if (
295	          row.widthMm === nextBox.widthMm &&
296	          row.heightMm === nextBox.heightMm &&
297	          row.xMm === nextBox.xMm &&
298	          row.yMm === nextBox.yMm
299	        ) {
300	          return prev;
301	        }
302	        const cp = [...prev];
303	        cp[rr.index] = { ...row, ...nextBox };
304	        return cp;
305	      });
306	    };
307	
308	    const onUp = () => {
309	      resizeRef.current = null;
310	      window.removeEventListener('pointermove', onMove);
311	      window.removeEventListener('pointerup', onUp);
312	      window.removeEventListener('pointercancel', onUp);
313	    };
314	
315	    window.addEventListener('pointermove', onMove);
316	    window.addEventListener('pointerup', onUp);
317	    window.addEventListener('pointercancel', onUp);
318	  };
319	
320	  return (
321	    <div
322	      data-testid="sheet-canvas"
323	      className={`overflow-auto rounded border border-border bg-background p-2${scrollCls}`}
324	    >
325	      <div data-testid="sheet-canvas-full-bleed">
326	        <svg
327	          ref={svgRef}
328	          data-testid="sheet-svg"
329	          viewBox={`0 0 ${wMm} ${hMm}`}
330	          className={bleed ? 'h-auto w-full' : 'h-auto max-h-[360px] w-full'}
331	          xmlns="http://www.w3.org/2000/svg"
332	        >
333	          <rect width={wMm} height={hMm} fill="#f8fafc" stroke="#1e293b" strokeWidth={120} />
334	          <rect x={800} y={800} width={wMm - 1600} height={3600} fill="#edf2ff" opacity={0.9} />
335	
336	          <text x={2400} y={2400} className="fill-slate-800" style={{ fontSize: '1200px' }}>
337	            A1 metaphor — {sh.name}
338	          </text>
339	
340	          <text x={2400} y={3600} className="fill-slate-500" style={{ fontSize: '800px' }}>
341	            TB {sh.titleBlock ?? '—'}
342	          </text>
343	
344	          {footerLines
345	            .map((txt) => txt.trim())
346	            .filter(Boolean)
347	            .map((txt, i) => (
348	              <text
349	                key={`tb-${i}-${txt.slice(0, 12)}`}
350	                x={xRight}
351	                y={footerY0 + i * 760}
352	                fill="#334155"
353	                style={{ fontSize: '620px' }}
354	                textAnchor="end"
355	              >
356	                {txt}
357	              </text>
358	            ))}
359	
360	          {revIssSeg ? (
361	            <text
362	              data-testid="sheet-canvas-revision-issue-doc-token"
363	              x={xRight}
364	              y={footerY0 + footerLines.map((txt) => txt.trim()).filter(Boolean).length * 760}
365	              fill="#0369a1"
366	              style={{ fontSize: '520px' }}
367	              textAnchor="end"
368	            >
369	              {revIssSeg}
370	            </text>
371	          ) : null}
372	
373	          {paintRows.map((row) => {
374	            const {
375	              xMm,
376	              yMm,
377	              widthMm,
378	              heightMm,
379	              viewRef,
380	              label,
381	              detailNumber,
382	              scale,
383	              viewportLocked,
384	              viewportRole,
385	              index,
386	            } = row;
387	            const resolved = resolveViewportTitleFromRef(elementsById, viewRef);
388	            const detailReason = detailCalloutUnresolvedReason(elementsById, viewRef);
389	            const isDetailCallout = viewportRole === 'detail_callout';
390	            const primary = isDetailCallout
391	              ? buildPlaceholderDetailTitle(detailNumber, resolved, detailReason)
392	              : resolved ?? label;
393	            const sub = viewRef.trim() ? viewRef : '';
394	            const parsedRef = parseSheetViewRef(viewRef);
395	            const secId =
396	              modelId && parsedRef?.kind === 'section' && parsedRef.refId
397	                ? parsedRef.refId
398	                : '';
399	
400	            const secInnerW = Math.max(200, widthMm - 320);
401	            const secInnerH = Math.max(200, heightMm - 2700);
402	
403	            const isScheduleVp = parsedRef?.kind === 'schedule' && Boolean(parsedRef.refId);
404	            const scheduleEl = isScheduleVp ? elementsById[parsedRef!.refId] : undefined;
405	            const scheduleResolved = scheduleEl?.kind === 'schedule';
406	            const scheduleCatRaw =
407	              scheduleResolved && scheduleEl.filters && typeof scheduleEl.filters === 'object'
408	                ? (scheduleEl.filters as Record<string, unknown>).category
409	                : undefined;
410	            const scheduleCat =
411	              typeof scheduleCatRaw === 'string' && scheduleCatRaw.trim()
412	                ? scheduleCatRaw.trim()
413	                : '';
414	            const scheduleCaption = isScheduleVp
415	              ? scheduleResolved
416	                ? `schedule · ${parsedRef!.refId}${scheduleCat ? ` · ${scheduleCat}` : ''}`
417	                : `unresolved schedule · ${parsedRef!.refId}`
418	              : '';
419	
420	            const planLegendHint = planLegendHints[row.key];
421	            const planLegendCaption =
422	              parsedRef?.kind === 'plan' && planLegendHint && planLegendHint.rowCount > 0
423	                ? `legend · ${planLegendHint.rowCount} rows · ${planLegendHint.digestPrefix}…`
424	                : '';
425	
426	            const handle = 560;
427	            const hx = xMm + widthMm - handle;
428	            const hy = yMm + heightMm - handle;
429	            const detailTrim = detailNumber.trim();
430	            const scaleTrim = scale.trim();
431	            const canDragResize = authoring && !viewportLocked;
432	            const vpStroke = isDetailCallout ? '#7c3aed' : '#475569';
433	            const vpDash =
434	              isDetailCallout || isScheduleVp ? '480 240' : undefined;
435	
436	            return (
437	              <g key={row.key}>
438	                <rect
439	                  data-testid={`sheet-viewport-${index}`}
440	                  x={xMm}
441	                  y={yMm}
442	                  width={widthMm}
443	                  height={heightMm}
444	                  fill="#ffffff"
445	                  stroke={vpStroke}
446	                  strokeWidth={80}
447	                  strokeDasharray={vpDash}
448	                  className={canDragResize ? 'cursor-move touch-none' : undefined}
449	                  onPointerDown={canDragResize ? (e) => beginDrag(e, index) : undefined}
450	                />
451	                {canDragResize ? (
452	                  <rect
453	                    data-testid={`sheet-viewport-resize-${index}`}
454	                    x={hx}
455	                    y={hy}
456	                    width={handle}
457	                    height={handle}
458	                    fill="#475569"
459	                    stroke="#1e293b"
460	                    strokeWidth={40}
461	                    className="cursor-nwse-resize touch-none"
462	                    onPointerDown={(e) => beginResize(e, index)}
463	                  />
464	                ) : null}
465	                {secId ? (
466	                  <svg
467	                    x={xMm + 160}
468	                    y={yMm + 1500}
469	                    width={secInnerW}
470	                    height={secInnerH}
471	                    viewBox={`0 0 ${secInnerW} ${secInnerH}`}
472	                  >
473	                    <SectionViewportSvg
474	                      modelId={modelId!}
475	                      sectionCutId={secId}
476	                      widthPx={secInnerW}
477	                      heightPx={secInnerH}
478	                    />
479	                  </svg>
480	                ) : null}
481	                {isDetailCallout ? (
482	                  <text
483	                    x={xMm + 200}
484	                    y={yMm + 520}
485	                    fill="#7c3aed"
486	                    style={{ fontSize: '320px' }}
487	                  >
488	                    detail callout
489	                  </text>
490	                ) : null}
491	                <text x={xMm + 200} y={yMm + 900} fill="#475569" style={{ fontSize: '600px' }}>
492	                  {primary}
493	                </text>
494	                {detailTrim ? (
495	                  <text
496	                    data-testid={`sheet-viewport-detail-${index}`}
497	                    x={xMm + widthMm - 200}
498	                    y={yMm + 820}
499	                    fill="#475569"
500	                    style={{ fontSize: '480px' }}
501	                    textAnchor="end"
502	                  >
503	                    {detailTrim}
504	                  </text>
505	                ) : null}
506	                {sub ? (
507	                  <text x={xMm + 200} y={yMm + 1400} fill="#64748b" style={{ fontSize: '350px' }}>
508	                    {sub}
509	                  </text>
510	                ) : null}
511	                {scaleTrim ? (
512	                  <text
513	                    data-testid={`sheet-viewport-scale-${index}`}
514	                    x={xMm + 200}
515	                    y={yMm + 1800}
516	                    fill="#64748b"
517	                    style={{ fontSize: '340px' }}
518	                  >
519	                    scale {scaleTrim}
520	                  </text>
521	                ) : null}
522	                {authoring && viewportLocked ? (
523	                  <text
524	                    x={xMm + widthMm - 200}
525	                    y={yMm + heightMm - 320}
526	                    fill="#94a3b8"
527	                    style={{ fontSize: '280px' }}
528	                    textAnchor="end"
529	                  >
530	                    locked
531	                  </text>
532	                ) : null}
533	                {scheduleCaption ? (
534	                  <text
535	                    data-testid={`sheet-viewport-schedule-caption-${index}`}
536	                    x={xMm + 200}
537	                    y={yMm + 2200}
538	                    fill={scheduleResolved ? '#15803d' : '#b45309'}
539	                    style={{ fontSize: '320px' }}
540	                  >
541	                    {scheduleCaption}
542	                  </text>
543	                ) : null}
544	                {planLegendCaption ? (
545	                  <text
546	                    data-testid={`sheet-viewport-plan-legend-caption-${index}`}
547	                    x={xMm + 200}
548	                    y={yMm + 2600}
549	                    fill="#0e7490"
550	                    style={{ fontSize: '300px' }}
551	                  >
552	                    {planLegendCaption}
553	                  </text>
554	                ) : null}
555	              </g>
556	            );
557	          })}
558	        </svg>
559	      </div>
560	
561	      <SheetDocumentationManifest
562	        sheet={sh}
563	        modelId={modelId}
564	        elementsById={elementsById}
565	        authoring={authoring}
566	        tbDraft={tbDraft}
567	        vpDrafts={vpDrafts}
568	      />
569	
570	      {props.onUpsertSemantic ? (
571	        <>
572	          <SheetTitleblockEditor
573	            sheetId={sh.id}
574	            sheetName={sh.name}
575	            draft={tbDraft}
576	            priorTitleblockParameters={tp as Record<string, string>}
577	            setDraft={setTbDraft}
578	            onUpsertSemantic={props.onUpsertSemantic}
579	          />
580	
581	          <SheetViewportEditor
582	            sheetId={sh.id}
583	            sheetName={sh.name}
584	            drafts={vpDrafts}
585	            setDrafts={setVpDrafts}
586	            elementsById={elementsById}
587	            onUpsertSemantic={props.onUpsertSemantic}
588	          />
589	        </>
590	      ) : null}
591	
592	      <div className="mt-1 font-mono text-[10px] text-muted">{sh.id}</div>
593	    </div>
594	  );
595	}
596	
597	/** Paper-space preview: titleblock stripe + viewport frames from semantic `sheet` elements. */
598	
599	export function SheetCanvas(props: {
600	  elementsById: Record<string, Element>;
601	  preferredSheetId?: string;
602	  modelId?: string;
603	  /**
604	   * When true, drop scroll/max-height clamps so PNG evidence can rasterize the entire sheet SVG
605	   * (drive via `/?evidenceSheetFull=1` in Playwright).
606	   */
607	  evidenceFullBleed?: boolean;
608	  /** When set, show a replayable `upsertSheetViewports` authoring band (WP-E05/E06/E04). */
609	  onUpsertSemantic?: (cmd: Record<string, unknown>) => void;
610	}) {
611	  const sheets = Object.values(props.elementsById).filter(
612	    (e): e is Extract<Element, { kind: 'sheet' }> => e.kind === 'sheet',
613	  );
614	
615	  const sh =
616	    sheets.find((s) => s.id === props.preferredSheetId) ??
617	    [...sheets].sort((a, b) => a.name.localeCompare(b.name))[0];
618	
619	  const sheetAuthoringSyncKey = useMemo(
620	    () =>
621	      sh
622	        ? JSON.stringify({
623	            tb: sh.titleblockParameters ?? {},
624	            tbsym: sh.titleBlock ?? '',
625	            vps: sh.viewportsMm ?? [],
626	          })
627	        : '',
628	    [sh],
629	  );
630	
631	  if (!sh) {
632	    return <div className="text-[11px] text-muted">No sheet elements in this model.</div>;
633	  }
634	
635	  return (
636	    <SheetCanvasWithSheet
637	      key={`${sh.id}:${sheetAuthoringSyncKey}`}
638	      sheet={sh}
639	      evidenceFullBleed={props.evidenceFullBleed}
640	      modelId={props.modelId}
641	      elementsById={props.elementsById}
642	      onUpsertSemantic={props.onUpsertSemantic}
643	    />
644	  );
645	}
