1041	      targetId: lvl.id,
1042	      label: kind === 'plan' ? `Plan · ${lvl.name}` : `Plan + 3D · ${lvl.name}`,
1043	    };
1044	  }
1045	  if (kind === '3d') {
1046	    const vp = all.find(
1047	      (e): e is Extract<Element, { kind: 'viewpoint' }> => e.kind === 'viewpoint',
1048	    );
1049	    if (vp) return { targetId: vp.id, label: `3D · ${vp.name}` };
1050	    return { label: '3D · Default' };
1051	  }
