38	
39	export function SectionModeShell({
40	  elementsById,
41	}: {
42	  elementsById: Record<string, Element>;
43	}): JSX.Element {
44	  const sections = asArr(elementsById, 'section_cut');
45	  const [activeId, setActiveId] = useState<string | null>(
46	    sections[0]?.id ?? SECTION_ELEVATION_DEFAULTS.activeSectionId,
47	  );
48	  const active = activeId ? elementsById[activeId] : undefined;
49	
50	  return (
51	    <div
52	      data-testid="section-mode-shell"
53	      className="grid h-full w-full"
54	      style={{ gridTemplateColumns: '1fr 1fr' }}
55	    >
56	      <div className="flex flex-col gap-2 overflow-y-auto border-r border-border bg-surface px-3 py-3">
57	        <div
58	          className="text-xs uppercase text-muted"
59	          style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
60	        >
61	          Section cuts
62	        </div>
63	        {sections.length === 0 ? (
64	          <p className="text-sm text-muted">No section cuts in the document.</p>
65	        ) : (
66	          <ul className="flex flex-col gap-1">
67	            {sections.map((s) => (
68	              <li key={s.id}>
69	                <button
70	                  type="button"
71	                  onClick={() => setActiveId(s.id)}
72	                  data-active={activeId === s.id ? 'true' : 'false'}
73	                  className={[
74	                    'w-full rounded-md px-3 py-1.5 text-left text-sm',
75	                    activeId === s.id
76	                      ? 'bg-accent-soft text-foreground'
77	                      : 'text-foreground hover:bg-surface-strong',
78	                  ].join(' ')}
79	                >
80	                  {s.name}
81	                </button>
82	              </li>
83	            ))}
84	          </ul>
85	        )}
86	      </div>
87	      <div className="flex flex-col items-stretch overflow-hidden bg-background">
88	        {active && active.kind === 'section_cut' ? (
89	          <SectionPreview section={active} />
90	        ) : (
91	          <PlaceholderCard
92	            title="Pick a section cut"
93	            body="Select a section on the left to draft its preview here."
94	            icon={Icons.section}
95	          />
96	        )}
97	      </div>
98	    </div>
99	  );
100	}
101	
102	function SectionPreview({
103	  section,
104	}: {
105	  section: Extract<Element, { kind: 'section_cut' }>;
106	}): JSX.Element {
107	  return (
108	    <div className="flex flex-1 flex-col gap-3 px-4 py-4 text-sm">
109	      <div className="text-md font-medium text-foreground">{section.name}</div>
110	      <div
111	        className="text-xs uppercase text-muted"
112	        style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
113	      >
114	        Section line · mm
115	      </div>
116	      <ul className="font-mono text-xs text-foreground">
117	        <li>
118	          start · ({section.lineStartMm.xMm}, {section.lineStartMm.yMm})
119	        </li>
120	        <li>
121	          end · ({section.lineEndMm.xMm}, {section.lineEndMm.yMm})
122	        </li>
123	        <li>crop depth · {section.cropDepthMm}</li>
124	      </ul>
125	      <div
126	        className="mt-3 flex-1 rounded-lg border border-border bg-draft-paper"
127	        style={{ background: 'var(--draft-paper)' }}
128	      >
129	        <p className="m-3 text-xs text-muted">
130	          Section preview canvas mounts here once the §20.4 SVG renderer lands.
131	        </p>
132	      </div>
133	    </div>
134	  );
135	}
136	
137	/* ────────────────────────────────────────────────────────────────────── */
138	/* Sheet mode (§20.5)                                                       */
